test_that("run_pca works", {
  
  data(iris)
  iris_num <- iris[, 1:4]

  res <- run_pca(
    numerics    = iris_num,
    active_cols = c("Sepal.Length", "Sepal.Width")
  )

  expect_s3_class(res, "PCA")
  expect_true(!is.null(res$eig))
  expect_true(ncol(res$ind$coord) <= 2)
    
  #---------------------------------------------------
  
  res <- run_pca(
    numerics    = iris_num,
    active_cols = c("Sepal.Length", "Sepal.Width"),
    supp_vars   = c("Petal.Length", "Petal.Width")
  )

  expect_s3_class(res, "PCA")
  expect_true(!is.null(res$quanti.sup))
  
  #---------------------------------------------------

  train <- iris_num[1:100, ]
  supp  <- iris_num[101:110, ]

  res <- run_pca(
    numerics    = train,
    active_cols = c("Sepal.Length", "Sepal.Width"),
    supp_inds   = supp
  )

  expect_s3_class(res, "PCA")
  expect_true(!is.null(res$ind.sup))
  
  #---------------------------------------------------

  train <- iris_num[1:100, ]
  supp  <- iris_num[101:110, ]

  res <- run_pca(
    numerics    = train,
    active_cols = c("Sepal.Length", "Sepal.Width"),
    supp_vars   = c("Petal.Length", "Petal.Width"),
    supp_inds   = supp
  )

  expect_s3_class(res, "PCA")
  expect_true(!is.null(res$quanti.sup))
  expect_true(!is.null(res$ind.sup))
  
})

test_that("plot_screeplot works", {

  data(iris)

  res_pca <- FactoMineR::PCA(iris[, 1:4], graph = FALSE)

  p <- plot_screeplot(res_pca)

  expect_s3_class(p, "ggplot")
  
  #---------------------------------------------------------------------

  res_pca <- FactoMineR::PCA(iris[, 1:2], graph = FALSE)

  p <- plot_screeplot(res_pca)

  expect_s3_class(p, "ggplot")

  #---------------------------------------------------------------------

  res_pca <- FactoMineR::PCA(iris[, 1:4], graph = FALSE)

  p <- plot_screeplot(res_pca)

  max_eig <- max(res_pca$eig[, 2])

  # Extract y range from ggplot object
  y_range <- ggplot2::ggplot_build(p)$layout$panel_scales_y[[1]]$range$range

  expect_equal(max(y_range), max_eig)

 })

