  expect_s3_class(p, "ggplot")
  
  
})


test_that("plot_bivariate handles iris-based PCA and verifies labels", {
  
  # 1. Setup data with iris
  # Using first 140 as active, last 10 as supplementary
  data_active <- iris[1:140, 1:4]
  data_sup    <- iris[141:150, 1:4]
  full_data   <- rbind(data_active, data_sup)
  
  # Run PCA
  res_pca <- FactoMineR::PCA(full_data, ind.sup = 141:150, graph = FALSE)
  
  # Prepare factors
  fac_df <- data.frame(
    Species   = iris$Species,
    row.names = rownames(iris)
  )
  
  # 2. Execute function
  p <- plot_bivariate(res_pca, fac_df, "Species")
  
  # --- Assertions ---
  
  # Verify object type
  expect_s3_class(p, "ggplot")
  
  # To avoid the NULL issue with labels, we can check the labs list directly 
  # or verify the scale aesthetics
  expect_equal(p$labels$colour, "Species")
  
  # Check if "supp. ind." is present in the plot data
  # Since we added it to ind_sup$group, we check the layers
  has_supp_layer <- any(sapply(p$layers, function(l) {
    if(!is.null(l$data)) return("supp. ind." %in% l$data$group)
    return(FALSE)
  }))
  expect_true(has_supp_layer)
  
  # Verify variance percentage is present in X label
  # Dim 1 for iris is approx 73.0%
  expected_pct <- paste0(round(res_pca$eig[1, 2], 1), "%")
  expect_match(p$labels$x, expected_pct)
  
  # Check for error when column is missing
  expect_error(
    plot_bivariate(res_pca, fac_df, "Unknown"),
    "factor_col must be a column name of factors"
  )
})

